import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../etc/passwd";
        String baseDirectory = "/var/data/";
        String normalizedPath = Paths.get(baseDirectory, userInput).normalize().toString();

        if (!normalizedPath.startsWith(baseDirectory)) {
            System.out.println("Invalid path specified.");
            return;
        }

        File file = new File(normalizedPath);

        if (file.exists()) {
            try (FileInputStream fis = new FileInputStream(file)) {
                int content;
                while ((content = fis.read()) != -1) {
                    System.out.print((char) content);
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        } else {
            System.out.println("File not found.");
        }
    }
}

